--
-- Table structure for table `venta_cliente`
--

DROP TABLE IF EXISTS `venta_cliente`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `venta_cliente` (
  `id_venta_cliente` int NOT NULL AUTO_INCREMENT,
  `id_usuario` int NOT NULL,
  `nro_pedido` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Número único del pedido (ej: PED-2025-00001)',
  `estado` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDIENTE' COMMENT 'PENDIENTE, PAGADO, PROCESANDO, ENVIADO, ENTREGADO, CANCELADO',
  `fecha_pedido` datetime NOT NULL COMMENT 'Fecha y hora cuando se crea el pedido',
  `fecha_entrega_estimada` date DEFAULT NULL COMMENT 'Fecha estimada de entrega según tipo de envío',
  `subtotal` decimal(10,2) NOT NULL COMMENT 'Suma de todos los productos (sin envío)',
  `costo_envio` decimal(10,2) DEFAULT '0.00' COMMENT 'Costo del envío según tipo',
  `total` decimal(10,2) NOT NULL COMMENT 'Subtotal + costo_envio',
  `dni_cliente` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'DNI o RUC del cliente',
  `nombre_cliente` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nombre del cliente',
  `apellido_cliente` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Apellido del cliente',
  `email_cliente` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Email del cliente',
  `telefono_cliente` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Teléfono de contacto',
  `direccion_envio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Dirección completa',
  `numero_calle` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Número de la calle',
  `apartamento` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Apartamento, bloque, piso',
  `ciudad` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ciudad de destino',
  `departamento` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Departamento/Región',
  `codigo_postal` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Código postal',
  `tipo_envio` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'NORMAL (5 días), EXPRESS (2 días), SAME_DAY (1 día)',
  `numero_seguimiento` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Número de seguimiento del courier',
  `tipo_pago` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'TARJETA_CREDITO, TARJETA_DEBITO, TRANSFERENCIA, YAPE, PLIN',
  `tipo_tarjeta` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'VISA, MASTERCARD, AMERICAN_EXPRESS (solo si es tarjeta)',
  `ultimos_4_digitos` varchar(4) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '⚠️ SOLO últimos 4 dígitos (nunca guardar tarjeta completa)',
  `banco_tarjeta` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Banco emisor de la tarjeta',
  `nombre_titular` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Nombre del titular de la tarjeta',
  `observaciones` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Notas adicionales del cliente (ej: entregar después de 6 PM)',
  `fecha_actualizacion` datetime DEFAULT NULL COMMENT 'Última vez que se actualizó el estado',
  `fecha_entrega_real` datetime DEFAULT NULL COMMENT 'Fecha real de entrega (cuando estado = ENTREGADO)',
  PRIMARY KEY (`id_venta_cliente`),
  UNIQUE KEY `nro_pedido` (`nro_pedido`),
  KEY `idx_id_usuario` (`id_usuario`),
  KEY `idx_estado` (`estado`),
  KEY `idx_fecha_pedido` (`fecha_pedido`),
  KEY `idx_nro_pedido` (`nro_pedido`),
  CONSTRAINT `fk_venta_cliente_usuario` FOREIGN KEY (`id_usuario`) REFERENCES `usuarios` (`id_usuario`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=120 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

